			copyTestAudioFile(nestedDir, "test.flac")

			// Execute: Scan library
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert: All files in nested directories should be found
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(2)))

			allFiles, err := ds.MediaFile(ctx).GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(2))

			// Verify paths contain the full directory structure
			for _, mf := range allFiles {
				Expect(mf.Path).To(ContainSubstring("Artist"))
				Expect(mf.Path).To(ContainSubstring("Album"))
			}
		})
	})

	Describe("Progress Tracking", func() {
		It("reports file counts through progress channel", func() {
			// Setup: Create multiple files
			copyTestAudioFile(testDir, "test.mp3")
			copyTestAudioFile(testDir, "test.flac")
			copyTestAudioFile(testDir, "test.m4a")

			// Execute: Scan and collect progress reports
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(3)))

			// Collect progress values
			var progressUpdates []uint32
			for p := range progress {
				progressUpdates = append(progressUpdates, p)
			}
			// Progress should have been reported at least once
			Expect(progressUpdates).NotTo(BeEmpty())
		})
	})
})

// Helper function to copy test audio files from fixtures
func copyTestAudioFile(destDir, filename string) {
	srcPath := filepath.Join("tests", "fixtures", filename)
	destPath := filepath.Join(destDir, filename)

	src, err := os.Open(srcPath)
	Expect(err).NotTo(HaveOccurred())
	defer src.Close()

	dest, err := os.Create(destPath)
	Expect(err).NotTo(HaveOccurred())
	defer dest.Close()

	_, err = io.Copy(dest, src)
	Expect(err).NotTo(HaveOccurred())
}

